import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,f as t}from"./app-e8ffb458.js";const o={},p=t(`<h3 id="有哪些数据类型" tabindex="-1"><a class="header-anchor" href="#有哪些数据类型" aria-hidden="true">#</a> 有哪些数据类型？</h3><ol><li>基本类型：<code>Number</code> <code>String</code> <code>Boolean</code> <code>Null</code> <code>Undefined</code> <code>Symbol</code> <code>BigInt</code></li><li>引用类型：<code>Object</code> <code>Function</code> <code>Array</code> <code>Map</code> <code>Set</code></li><li>区别：是数据存储不同</li></ol><blockquote><p>a. 基本类型的值存储在栈中，在栈中存储的是值，它赋值后值相同，但是两个值对应的地址不同，所以<code>a = 1;b=a;a=2;b还是等于1；</code><br> b. 引用类型的值存储在堆中，在栈存放的是指向堆内存的指针地址；它赋值时候是将对象的内存地址赋值給另一个对象，也就是说两个对象指向的是同一个堆内存，所以<code>a={name:11};b=a;b.name=22; a也会改变；</code></p></blockquote><h3 id="null与undefined区别是什么" tabindex="-1"><a class="header-anchor" href="#null与undefined区别是什么" aria-hidden="true">#</a> null与undefined区别是什么？</h3><ol><li>①undefined代表定义未赋值；②nulll定义并赋值了, 只是值为null</li><li>typeof null是object</li><li>什么时候给变量赋值为null呢?①初始赋值, 表明将要赋值为对象；②结束前, 让对象成为垃圾对象(被垃圾回收器回收)</li><li>null==undefined; null!==undefined</li></ol><h3 id="symbol创建唯一值" tabindex="-1"><a class="header-anchor" href="#symbol创建唯一值" aria-hidden="true">#</a> Symbol创建唯一值</h3><ol><li>是什么？给对象设置“唯一值&quot;的属性名，对象的属性名可以是数字、字符串、Symbol类型；</li><li>用法？</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> a1<span class="token operator">=</span> <span class="token function">symbol</span><span class="token punctuation">(</span><span class="token string">&#39;AA&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
<span class="token keyword">let</span> a2<span class="token operator">=</span> <span class="token function">symbol</span><span class="token punctuation">(</span><span class="token string">&#39;AA&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
<span class="token keyword">let</span> a3 <span class="token operator">=</span> a1<span class="token punctuation">;</span> 
a1 <span class="token operator">===</span> a2<span class="token punctuation">;</span> <span class="token comment">//false </span>
a1 <span class="token operator">===</span> a3 <span class="token comment">//true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>作用？ <code>Symbol.asyncIterator/iterator/hasInstance/toPrimitive/tostringTag </code>是某些js底层原理的实现机制。基于symbol类型的值，保证行为标识的唯一性</li></ol><h3 id="bigint大数类型" tabindex="-1"><a class="header-anchor" href="#bigint大数类型" aria-hidden="true">#</a> BigInt大数类型</h3><ol><li>超过安全数后，进行运算或者访问，结果会不准确</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code> a<span class="token punctuation">.</span> Number<span class="token punctuation">.</span><span class="token constant">MAX_SAFE_INTEGER</span><span class="token operator">:</span> <span class="token number">9007199254740991</span> <span class="token comment">//jS中的最大安全数</span>
 b<span class="token punctuation">.</span> Number<span class="token punctuation">.</span><span class="token constant">MIN_SAFE_INTEGER</span><span class="token operator">:</span> <span class="token operator">-</span><span class="token number">9007199254740991</span> <span class="token comment">//jS中的最小安全数</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>解决方案<br> a. 服务器返回给客户端的大数，按照&quot;字符串&quot;格式返回；然后客户端把其变为 BigInt，然后按照BigInt进行运算,最后把运算后的BigInt转换为字符串，在传递给服务器即可</li></ol><h3 id="数据类型的检测方式有哪些" tabindex="-1"><a class="header-anchor" href="#数据类型的检测方式有哪些" aria-hidden="true">#</a> 数据类型的检测方式有哪些？</h3><ol><li><code>typeof</code>：其中数组、对象、null 都会被判断为 object</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// number</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// boolean</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token string">&quot;str&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// string</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token keyword">undefined</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// function</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// object</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// object</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// object</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><ul><li>数据类型的值在计算机底层是按照64位的二进制值进行存储的，typeof也是按照二进制进行类型检测。</li><li>前三位是0认为是对象，然后再去看有没有实现call方法。如果实现了则返回&#39;function&#39;，没有实现，则返回&#39;object&#39;。null是64个零,所以typeof null-&gt;&#39;object&#39;</li></ul></blockquote><ol start="2"><li><code>instanceof</code>：可以判断对象的类型，不能判断基本类型的；原理是构造函数的prototype属性是否出现在对象原型链的任何位置。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">2</span> <span class="token keyword">instanceof</span> <span class="token class-name">Number</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token boolean">true</span> <span class="token keyword">instanceof</span> <span class="token class-name">Boolean</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;str&quot;</span> <span class="token keyword">instanceof</span> <span class="token class-name">String</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// false</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token keyword">instanceof</span> <span class="token class-name">Array</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token keyword">instanceof</span> <span class="token class-name">Function</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token keyword">instanceof</span> <span class="token class-name">Object</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><ul><li>先检测构造函数是否拥有 Symbol.hasInstance 方法</li><li>如果有这个方法:构造函数<code>[Symbol.hasInstance](实例)</code>返回的值就是结果；</li><li>如果没有这个方法，则按照原型链进行查找:按照实例的_proto-一直向上找，直到找到0bject.prototype为止，只要在原型链上出现了“构造函数.prototype”，说明当前实例率属于它，结果返回true;如果没找到，结果就是false;</li></ul></blockquote><ol start="3"><li><code>constructor</code>:判断两种数据的类型，对象实例通过constructor来访问它的构造函数，缺点是如果对象改变过它的原型，那么constructor判断会有问题</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">.</span>constructor <span class="token operator">===</span> Number<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">.</span>constructor <span class="token operator">===</span> Boolean<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>constructor <span class="token operator">===</span> String<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">.</span>constructor <span class="token operator">===</span> Array<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span>constructor <span class="token operator">===</span> Function<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span>constructor <span class="token operator">===</span> Object<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="4"><li><code>Object.prototype.toString.call([value])</code>：使用Object对象的原型方法toString来判断数据类型,属于检测最准确、最全面的方式了，能够区分null、能够检测原始值类型、能够细分对象、即便重构原型对象检测也是准确的</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>        <span class="token comment">//&#39;[object Number]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">//&#39;[object Boolean]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token string">&quot;str&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>    <span class="token comment">//&#39;[object String]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>       <span class="token comment">//&#39;[object Array]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//&#39;[object Function]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>       <span class="token comment">//&#39;[object Object]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token keyword">undefined</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//&#39;[object Undefined]&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token class-name">Object</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">//&#39;[object Null]&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><ul><li>返回结果“[object ?] ?：一般是自己所属的构造函数</li><li>首先会看[value]值是否有 Symbol.tostringTag 属性，有这个属性，属性值是啥，检测出来是啥就是啥; <code>Math[Symbol.tostringTag]:&#39;Math&#39;</code> <code>map.prototype[Symbol.tostringTag]:&#39;Map&#39;</code> <code>Promise.prototype[Symbol.tostringTag]:&#39;Promise&#39;</code> <code>Set.prototype[Symbol.tostringTag]:&#39;set&#39;</code></li><li>如果没有这个属性，才一般是按照自己所属的构造函数返回</li></ul></blockquote><h3 id="数组的判断有几种" tabindex="-1"><a class="header-anchor" href="#数组的判断有几种" aria-hidden="true">#</a> 数组的判断有几种？</h3><ol><li>Object.prototype.toString.call(): <code>Object.prototype.toString.call([]).slice(8,-1) === &quot;Array&quot;</code></li><li>Array.isArray(): <code>Array.isArray([])</code></li><li>instanceof: <code>[] instanceof Array</code></li><li>Array.prototype.isPrototypeOf：<code>Array.prototype.isPrototypeOf([])</code></li><li><code>__proto__</code>: <code>[].__proto__ === Array.prototype</code></li></ol><h3 id="typeof-nan是多少" tabindex="-1"><a class="header-anchor" href="#typeof-nan是多少" aria-hidden="true">#</a> typeof NaN是多少？</h3><ol><li>typeof NaN是number</li><li>NaN:指不是一个数字，意思是执行数字运行失败，是失败后返回的结果</li><li>NaN === NaN 为false</li></ol><h3 id="instanceof操作符的实现原理" tabindex="-1"><a class="header-anchor" href="#instanceof操作符的实现原理" aria-hidden="true">#</a> instanceof操作符的实现原理？</h3><ol><li>作用：检测某个对象是否属于某个类型 <code>[] instanceof Array</code></li><li>原理是判断构造函数的prototype属性是否出现在对象原型链的任何位置；所以重点就是找到递归对象的原型链以及构造函数的prototype</li><li>步骤</li></ol><blockquote><p>a. 获取对象的原型 <code>proto = Object.getPrototypeOf(obj)</code><br> b. 获取构造函数的原型对象 <code>prototype = ctor.prototype;</code><br> c. 判断构造函数的原型对象是否在对象的原型链上 <code>proto === prototype</code><br> d. 如果没有找到就继续在其原型上找 <code>proto = Object.getPrototypeOf(proto);</code></p></blockquote><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">myInstanceof</span><span class="token punctuation">(</span><span class="token parameter">obj<span class="token punctuation">,</span> ctor</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 获取对象的原型</span>
  <span class="token keyword">let</span> proto <span class="token operator">=</span> Object<span class="token punctuation">.</span><span class="token function">getPrototypeOf</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token comment">// 获取构造函数的 prototype 对象</span>
  <span class="token keyword">let</span> prototype <span class="token operator">=</span> ctor<span class="token punctuation">.</span>prototype<span class="token punctuation">;</span>
  <span class="token comment">// 判断构造函数的 prototype 对象是否在对象的原型链上</span>
  <span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>proto<span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>proto <span class="token operator">===</span> prototype<span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token comment">// 如果没有找到，就继续从其原型上找，Object.getPrototypeOf方法用来获取指定对象的原型</span>
    proto <span class="token operator">=</span> Object<span class="token punctuation">.</span><span class="token function">getPrototypeOf</span><span class="token punctuation">(</span>proto<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="类型转换机制" tabindex="-1"><a class="header-anchor" href="#类型转换机制" aria-hidden="true">#</a> 类型转换机制?</h3><ol><li>常见的类型转换有：强制转换（显式转换）、自动转换（隐式转换）</li><li>显式转换转化规则常见的方法有：<code>Number() parseInt() parseFloat() String() Boolean()</code></li><li>隐式转换转化规则？比较运算<code>（==、!=、&gt;、&lt;）if、while</code>；算术运算<code>（+、-、*、/、%）</code></li><li>其他类型转数字: ①<code>Number([val])</code>：比较严格，只要有一个字符无法转成数值，整个字符串就会被转为NaN； ②<code>parseInt([val], [radix])</code>：没那么严格，遇到不能转换的字符就停下来。</li></ol><blockquote><ol><li>空字符串为0，有出现非数字结果为NaN</li><li>布尔值转数字，true:1,false:0</li><li>Symbol会报错；</li><li>null:0; undefined:NaN；</li><li>BigInt去除“n”</li><li>对象转数字：①先调用对象原型上的一个函数<code>Symbol.toPrimitive()</code>②如果不存在则调用对象的<code>valueOf</code>获取原始值；③如果获取的不是原始值，再调用对象的<code>toString</code>转为字符串；④再把字符串基于<code>Number</code>方法转换为数字；</li></ol></blockquote><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">Number</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">//10</span>
<span class="token comment">// 1 首先检测Symbol.toPrimitive是否存在，如果存在就调用 ƒ [Symbol.toPrimitive]() { [native code] }</span>
<span class="token comment">// 2 如果是undefined，那么arr.valueOf()获取原始值 </span>
<span class="token comment">// 3 结果为[10]，不是原始值，那么就是arr.toString()转为字符串‘10’;</span>
<span class="token comment">// 4 最后再把字符串转为数字 Number(&#39;10&#39;)-&gt;10</span>
<span class="token comment">// Number([10, 20])结果为NaN,分析如下：</span>
<span class="token comment">//  [10,20].valueOf():[10, 20]-&gt; [10,20].toString():&#39;10,20&#39; -&gt; Number(&#39;10,20&#39;)-&gt;NaN</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="5"><li>其他类型转字符串:①拿字符串包起来<code>String({}) //&#39;[object Object]&#39;</code>; ②“+”出现在两边，其中一边是字符串或者某些对象，会以字符串拼接规则处理</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token operator">+</span><span class="token string">&#39;10&#39;</span><span class="token punctuation">)</span> <span class="token comment">//&#39;1010&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token operator">+</span><span class="token keyword">new</span> <span class="token class-name">Number</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">//20</span>
<span class="token comment">//①new Number(10)[Symbol.toPrimitive]:undefined；-&gt; ②new Number(10).value0f():10 -&gt; 10+10 = 20</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token operator">+</span><span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">//&#39;1010&#39; </span>
<span class="token comment">//①[10][Symbol.toPrimitive]:undefined；-&gt; ②[10].valueOf().toString():&#39;10&#39;，为字符串，所以是拼接 </span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="6"><li>其他类型转布尔值: <code>Boolean([val])或者!/!!</code> 除了<code>null undefined &#39;&#39; NaN</code>，其他结果都是true。</li></ol><h3 id="toprimitive-用来将值转换为基本类型值" tabindex="-1"><a class="header-anchor" href="#toprimitive-用来将值转换为基本类型值" aria-hidden="true">#</a> ToPrimitive: 用来将值转换为基本类型值</h3><ol><li>如果值为对象，ToPrimitive(obj, type);对象默认type为number。</li><li>当type为number时规则：<code>var objToNumber = (value) =&gt; Number(value.valueOf().toString());</code></li><li>当type为string时规则：<code>var objToNumber = (value) =&gt; Number(value.toString().valueOf());</code></li><li>对于 Date 以外的对象，转换为基本类型的大概规则可以概括为一个函数：<code>var objToNumber = (value) =&gt; Number(value.valueOf().toString());</code></li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> a <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Tom&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token keyword">var</span> b <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">age</span><span class="token operator">:</span> <span class="token number">18</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
a <span class="token operator">+</span> b<span class="token punctuation">;</span> <span class="token comment">// &quot;[object Object][object Object]&quot;</span>
a<span class="token punctuation">.</span><span class="token function">valueOf</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// &quot;[object Object]&quot;</span>
b<span class="token punctuation">.</span><span class="token function">valueOf</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// &quot;[object Object]&quot;</span>
a <span class="token operator">+</span> b<span class="token punctuation">;</span> <span class="token comment">// &quot;[object Object][object Object]&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="操作符的强制类型转换规则" tabindex="-1"><a class="header-anchor" href="#操作符的强制类型转换规则" aria-hidden="true">#</a> ==操作符的强制类型转换规则？</h3><ol><li>首先会判断两者的类型是否一样，一样则比较大小；不一样则进行类型装换；</li><li>两个都为简单类型则有一方为字符串和布尔值都会转换成数值再进行判断；null==undefined是true;</li><li>两个都为引用类型则比较他们是否指向同一对象，比较的是堆内存地址，地址相同则相等</li><li>一个为引用类型，一个为复杂类型则将复杂类型用ToPrimitive转为原始类型再进行判断</li><li>除了以上情况，只要两边类型不一致，剩下的都是转换为数字，然后再进行比较的。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 一个为引用类型，一个为复杂类型</span>
<span class="token comment">//对象==字符串 需要将对象转字符串再比较「symbol.toPrimitive-&gt;value.toString().valueOf()]</span>
<span class="token comment">//对象==数字 需要将对象转数字再比较「symbol.toPrimitive-&gt;value.valueOf().toString()]</span>
<span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">==</span> <span class="token boolean">false</span> <span class="token comment">//true</span>
<span class="token comment">//只要两边类型不一致，剩下的都是转换为数字 Number([])为0，所以0 == 0为true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="为什么-0-1-0-2-0-3-如何让其相等" tabindex="-1"><a class="header-anchor" href="#为什么-0-1-0-2-0-3-如何让其相等" aria-hidden="true">#</a> 为什么 0.1+0.2 ! == 0.3，如何让其相等？</h3><ol><li>为什么小数（浮点数）的计算会出现精准度丢失问题？<code>0.1+0.2 // 0.30000000000000004</code> <code>0.1+0.7 //0.7999999999999999</code></li></ol><blockquote><ul><li>计算机存储值是以二进制在计算机底层来存的，所以需要先把十进制转为二进制的科学计数法<code>n.toString(2)</code></li><li>整数：(10).toString(2) //&#39;1010&#39;-&gt;10一直去除以2，余数组合就是结果；</li><li>浮点数：(0.1).toString(2) //&#39;0.0001100110011001100110011001100110011001100110011001101&#39;</li><li>某些十进制的浮点数在转二进制可能会无限循环下去，在底层存储最多存64位，舍弃了一些值后值本身就失去了精准值，再转成十进制就有了误差；</li></ul></blockquote><ol start="2"><li>怎么解决精准度问题？使用 toPrecision 凑整；扩大系数法，把小数转成整数后再运算；使用第三方库，如Math.js、BigDecimal.js</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//扩大系数法,把小数转成整数后再运算</span>
<span class="token keyword">function</span> <span class="token function">add</span><span class="token punctuation">(</span><span class="token parameter">num1<span class="token punctuation">,</span> num2</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> num1Digits <span class="token operator">=</span> <span class="token punctuation">(</span>num1<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">split</span><span class="token punctuation">(</span><span class="token string">&#39;.&#39;</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">||</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>length<span class="token punctuation">;</span>
  <span class="token keyword">const</span> num2Digits <span class="token operator">=</span> <span class="token punctuation">(</span>num2<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">split</span><span class="token punctuation">(</span><span class="token string">&#39;.&#39;</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">||</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>length<span class="token punctuation">;</span>
  <span class="token keyword">const</span> baseNum <span class="token operator">=</span> Math<span class="token punctuation">.</span><span class="token function">pow</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">,</span> Math<span class="token punctuation">.</span><span class="token function">max</span><span class="token punctuation">(</span>num1Digits<span class="token punctuation">,</span> num2Digits<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token punctuation">(</span>num1 <span class="token operator">*</span> baseNum <span class="token operator">+</span> num2 <span class="token operator">*</span> baseNum<span class="token punctuation">)</span> <span class="token operator">/</span> baseNum<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,51),e=[p];function c(l,i){return s(),a("div",null,e)}const k=n(o,[["render",c],["__file","JavaScript有什么数据类型.html.vue"]]);export{k as default};
